48	static void print_help()
49	{
50	  print_version();
51	  fmt::print(R"(
52	Usage: sim_cpu_name [elf_file] [options]
53	
54	AndesCycle CPU simulator for RISC-V processors
55	
56	Argument:
57	  <elf_file>                  RISC-V ELF binary to simulate
58	
59	General:
60	  --help, -h                  Print this help message and exit
61	  --version                   Display version information and exit
62	  --print-config              Show CPU configuration and exit
63	  --print-memmap              Show memory map layout and exit
64	  --log-level <level>         Set logging verbosity [default: 2]
65	                              (0=trace 1=debug 2=info 3=warn 4=error 5=critical 6=off)
66	
67	Simulation:
68	  --mem-latency  <cycles>     Memory access latency in cycles [default: 1]
69	  --reset-vector <spec>       Set per-hart reset vector
70	                              <addr>        set all harts to <addr>
71	                              <hart>:<addr> set specific hart to <addr>
72	                              Overrides ELF entrypoint if specified
73	
74	Tracing:
75	  --pc-trace  <file>          Enable PC trace logging to CSV file
76	  --kanata    <file>          Enable Kanata pipeline visualization logging
77	  --clarity   <file>          Enable Clarity pipeline visualization logging
78	  --objdump   <file>          Load objdump disassembly for pipeline viewer labels
79	
80	Debug:
81	  --jtag-port <port>          JTAG remote bitbang port for OpenOCD [default: 9104]
82	
83	Extra Options (require additional license):
84	  --ilm       <image>         Load ILM ROM image
85	  --dlm       <image>         Load DLM ROM image
86	  --waveform  <file>          Enable VCD/FST waveform tracing
87	  --save                      Save context when CPU enters WFI
88	  --continue                  Restore context and resume execution
89	  --context-dir <dir>         Context directory [default: ./saved_ctx]
90	)");
91	  // --ilm/--dlm: CPU-specific, not all CPUs have ILM/DLM
92	  // --waveform: requires compile flag VSIMDEBUG
93	  // --save/--continue/--context-dir: requires compile flag VSIMSAVABLE
94	}
