96	extern "C" auto sc_main(const int argc, char* argv[]) -> int
97	try {
98	  spdlog::set_default_logger(spdlog::stderr_color_mt("stderr_logger"));
99	  spdlog::set_pattern("[%^%l%$] %v");
100	
101	  const auto args = [&] {
102	    struct args
103	    {
104	      std::string pc_trace_file{};
105	      std::string elf_file{};
106	      std::optional<uint16_t> jtag_port = std::nullopt;
107	      bool memmap = false;
108	      std::string waveform_file{};
109	      unsigned mem_latency = 1;
110	      std::string ilm_file{};
111	      std::string dlm_file{};
112	      std::string kanata_file{};
113	      std::string objdump_file{};
114	      std::string clarity_file{};
115	      std::vector<std::string> reset_vectors{};
116	      bool continue_ctx = false;
117	      bool save_ctx = false;
118	      std::string context_dir = "./saved_ctx/";
119	    } args;
120	
121	    const auto help_and_exit = [] {
122	      print_help();
123	      exit(0);
124	    };
125	
126	    auto p = parser{};
127	    p.shortflag('h', help_and_exit);
128	    p.longflag("help", help_and_exit);
129	    p.longflag("version", [] {
130	      print_version();
131	      exit(0);
132	    });
133	    p.longflag("print-memmap", [&] { args.memmap = true; });
134	    p.longflag("print-config", [] {
135	      print_cpu_configuration();
136	      exit(0);
137	    });
138	    p.longopt("jtag-port", [&](const std::string_view s) {
139	      if (auto n = to_int<uint16_t>(s); n)
140	        args.jtag_port = *n;
141	      else
142	        throw std::runtime_error("invalid number for --jtag-port: "
143	                                 + std::string{s});
144	    });
145	    p.longopt("mem-latency", [&](const std::string_view s) {
146	      if (auto n = to_int<unsigned>(s); n)
147	        args.mem_latency = *n;
148	      else
149	        throw std::runtime_error("invalid number for --mem-latency: "
150	                                 + std::string{s});
151	    });
152	    p.longopt("log-level", [](const std::string_view s) {
153	      if (auto n = to_int<uint16_t>(s); n) {
154	        *n = std::min(*n, (uint16_t) SPDLOG_LEVEL_OFF);
155	        spdlog::set_level(static_cast<spdlog::level::level_enum>(*n));
156	      } else {
157	        throw std::runtime_error("invalid number for --log-level: "
158	                                 + std::string{s});
159	      }
160	    });
161	    p.longopt("waveform",
162	              [&](const std::string_view s) { args.waveform_file = s; });
163	    p.longopt("ilm", [&](const std::string_view s) { args.ilm_file = s; });
164	    p.longopt("dlm", [&](const std::string_view s) { args.dlm_file = s; });
165	    p.longopt("pc-trace",
166	              [&](const std::string_view s) { args.pc_trace_file = s; });
167	    p.longopt("kanata",
168	              [&](const std::string_view s) { args.kanata_file = s; });
169	    p.longopt("objdump",
170	              [&](const std::string_view s) { args.objdump_file = s; });
171	    p.longopt("clarity",
172	              [&](const std::string_view s) { args.clarity_file = s; });
173	    p.longflag("continue", [&] { args.continue_ctx = true; });
174	    p.longflag("save", [&] { args.save_ctx = true; });
175	    p.longopt("context-dir",
176	              [&](const std::string_view s) { args.context_dir = s; });
177	    p.longopt("reset-vector", [&](const std::string_view s) {
178	      args.reset_vectors.emplace_back(s);
179	    });
180	    p.posarg([&](const std::string_view s) { args.elf_file = s; });
181	    p.parse(std::vector<std::string_view>(argv, argv + argc));
182	    return args;
183	  }();
184	
185	#ifndef VSIMSAVABLE
186	  if (args.save_ctx || args.continue_ctx || args.context_dir != "./saved_ctx/")
187	  {
188	    spdlog::critical(
189	      "--save, --continue, and --context-dir require VSIMSAVABLE build");
190	    std::exit(EXIT_FAILURE);
191	  }
192	#endif
193	
194	  print_version();
195	
196	  // systemc and cci init
197	  auto broker = cci_utils::broker{"global_broker"};
198	  cci::cci_register_broker(broker);
199	
200	  const auto time_resolution = sc_core::sc_get_time_resolution();
201	  spdlog::debug("Using time resolution: {}", time_resolution.to_string());
202	
203	  // run simulation
204	  const auto do_sim = [&]<typename CPU>() -> int {
205	    Simulator<CPU> sim{"sim"};
206	
207	    if (args.memmap) {
208	      sim.platform.interconnect.dump_region();
209	      return 0;
210	    }
211	
212	    sim.set_mem_latency(args.mem_latency);
213	
214	    if (!args.ilm_file.empty())
215	      sim.load_image(args.ilm_file, MEM_TYPE::ILM);
216	
217	    if (!args.dlm_file.empty())
218	      sim.load_image(args.dlm_file, MEM_TYPE::DLM);
219	
220	    // End of elaboration
221	    sc_core::sc_start(sc_core::SC_ZERO_TIME);
222	
223	    const auto t0 = std::chrono::steady_clock::now();
224	
225	    if (!args.waveform_file.empty())
226	      sim.enable_waveform(args.waveform_file);
227	
228	    if (!args.pc_trace_file.empty())
229	      sim.enable_pc_trace(args.pc_trace_file);
230	
231	    if (!args.kanata_file.empty() && !args.clarity_file.empty())
232	      throw std::runtime_error("--kanata and --clarity are mutually exclusive");
233	
234	    if (!args.kanata_file.empty())
235	      sim.enable_kanata(args.kanata_file, args.objdump_file);
236	
237	    if (!args.clarity_file.empty())
238	      sim.enable_clarity(args.clarity_file, args.objdump_file);
239	
240	    if (!args.elf_file.empty() && !args.continue_ctx)
241	      sim.load_elf(args.elf_file);
242	
243	    // Apply per-hart reset vector overrides (after load_elf sets defaults)
244	    for (const auto& s: args.reset_vectors) {
245	      auto [hart, addr] = parse_reset_vector(s);
246	      if (hart) {
247	        sim.set_reset_vector(*hart, addr);
248	      } else {
249	        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
250	          sim.set_reset_vector(i, addr);
251	      }
252	    }
253	
254	    if (args.continue_ctx)
255	      spdlog::info("You're resuming program from the given context");
256	
257	    if (args.jtag_port)
258	      sim.init_debug_port(args.jtag_port.value());
259	
260	    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx)
261	      throw std::runtime_error("Required arg : program or --jtag-port");
262	
263	    if (args.continue_ctx || args.save_ctx) {
264	      std::string_view s = args.context_dir;
265	      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
266	        throw std::runtime_error("Error: Path " + std::string{s}
267	                                 + " exists but is not a directory.");
268	      if (!std::filesystem::exists(s)) {
269	        try {
270	          std::filesystem::create_directories(s);
271	        } catch (const std::filesystem::filesystem_error& e) {
272	          throw std::runtime_error(std::string{"Failed to create directory: "}
273	                                   + e.what());
274	        }
275	      }
276	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
277	    }
278	
279	    sim.reset();
280	
281	    const int exit_code = sim.run();
282	
283	    sim.cpu.final();
284	
285	    const auto t1 = std::chrono::steady_clock::now();
286	    const auto cycles = sim.get_cycles();
287	    spdlog::info("{} cycles simulated", cycles);
288	    if (cycles > 0) {
289	      const auto ms =
290	        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
291	      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
292	                   ms.count() % 1000,
293	                   double(cycles) / double(ms.count()) * 1000.0);
294	    }
295	    return exit_code;
296	  };
297	
298	  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();
299	
300	} catch (const std::exception& e) {
301	  spdlog::critical("fatal exception: {}\n", e.what());
302	  std::exit(EXIT_FAILURE);
303	} catch (...) {
304	  std::terminate();
305	}
