24	template<typename CPU>
25	class Simulator : sc_core::sc_module
26	{
27	  using PLATFORM = Platform<platform_config<CPU>>;
28	  static constexpr bool is_axi = (CPU::SYSTEM_BUS_TYPE == BusTypes::AXI);
29	  static constexpr auto bus_width = PLATFORM::data_width;
30	
31	  // Helper: create an AXI→TLM bridge, bind clock, connect initiator BFM
32	  auto make_axi_to_tlm(const char* name, auto& bfm_socket)
33	    -> std::unique_ptr<axi_to_tlm_bridge<bus_width>>
34	  {
35	    auto bridge = std::make_unique<axi_to_tlm_bridge<bus_width>>(name);
36	    bridge->pe.clk_i.bind(platform.clk);
37	    bfm_socket.bind(bridge->axi_tsck);
38	    return bridge;
39	  }
40	
41	  // Helper: create a TLM→AXI bridge, bind clock, connect target BFM
42	  auto make_tlm_to_axi(const char* name, auto& bfm_socket)
43	    -> std::unique_ptr<tlm_to_axi_bridge<bus_width>>
44	  {
45	    auto bridge = std::make_unique<tlm_to_axi_bridge<bus_width>>(name);
46	    bridge->pe.clk_i.bind(platform.clk);
47	    bridge->axi_isck.bind(bfm_socket);
48	    return bridge;
49	  }
